What does this program print?

```cpp
#include <iostream>
int main() {
    auto sq = [](int x) { return x * x; };
    auto cube = [](int x) { return x * x * x; };
    std::cout << sq(4) << "\n";
    std::cout << cube(3) << "\n";
    std::cout << sq(cube(2)) << "\n";
}
```

